@spec vm_slot_writers_spec  src=tests/specs/vm_slot_writers_spec.lua  loc=207  sha=f5042ce  cases=18
@exercises trackerView (h.vm), configManager (h.cm), dataStore (h.ds)
@surface   vm:setTemperSlot, cm:getAt, vm:setSwingSlot, ds:get, vm:setSwingComposite, vm:setColSwingSlot, vm:seedSharedSlots, cm:set
@harness   mk

# Intent
  Pin the swing/temper slot-write contract: swing is the take's document-data map
  (defaultSwing is the config seed); temper is a view-only multi-tier config key.

# Cases
  @case 'setTemperSlot writes the pick to take, track and project tiers'  [harness]  @ 13-22
  @case 'setTemperSlot(nil) writes the 12EDO sentinel across the tiers'  [harness]  @ 25-31
  @case 'setTemperSlot("") writes the 12EDO sentinel across the tiers'  [harness]  @ 34-40
  @case 'setTemperSlot localizes a catalogue temper into the project library'  [harness]  @ 43-49
  @case 'setTemperSlot(nil) never localizes the 12EDO floor'  [harness]  @ 52-57
  @case 'setSwingSlot writes the take map global slot and seeds defaultSwing at project + track'  [harness]  @ 63-72
  @case 'setSwingSlot localizes a catalogue preset into the project library'  [harness]  @ 75-82
  @case 'setSwingSlot(nil) never localizes the identity floor'  [harness]  @ 85-90
  @case 'setSwingComposite always writes project (no global escape hatch)'  [harness]  @ 93-99
  @case 'setColSwingSlot localizes a catalogue preset into the project library'  [harness]  @ 102-107
  @case 'setSwingSlot(nil) writes the identity sentinel into the take map and seed'  [harness]  @ 110-116
  @case 'setColSwingSlot writes the channel into the take map and the track seed only'  [harness]  @ 122-131
  @case 'setColSwingSlot preserves entries on other channels'  [harness]  @ 134-145
  @case 'setColSwingSlot(chan, nil) removes only that channel'  [harness]  @ 148-159
  @case 'seedSharedSlots copies defaultSwing into a fresh take\'s swing map'  [harness]  @ 165-173
  @case 'seedSharedSlots does not overwrite a take that already has a swing map'  [harness]  @ 176-184
  @case 'seedSharedSlots materialises the identity floor when no seed tier is set'  [harness]  @ 187-192
  @case 'seedSharedSlots: a take left at Off is not re-seeded after the default changes'  [harness]  @ 197-205

